@Entity()
export class UserModeration {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @ManyToOne(() => User)
  @JoinColumn({ name: 'userId' })
  user: User;

  @Column()
  userId: string;

  @Column({ type: 'enum', enum: ['BLOCK', 'UNBLOCK', 'ROLE_CHANGE', 'ACTIVATE', 'DEACTIVATE'] })
  action: string;

  @Column({ type: 'text', nullable: true })
  reason: string; // Raison du blocage ou du changement

  @Column('simple-json', { nullable: true })
  previousState: {
    isActive: boolean;
    roles: string[];
  };

  @Column('simple-json', { nullable: true })
  newState: {
    isActive: boolean;
    roles: string[];
  };

  @ManyToOne(() => User)
  @JoinColumn({ name: 'moderatedById' })
  moderatedBy: User;

  @Column()
  moderatedById: string;

  @CreateDateColumn()
  moderatedAt: Date;

  @Column({ nullable: true })
  expiresAt: Date; // Pour les blocages temporaires
}
```
Justification : `previousState` et `newState` permettent de garder une trace complète des changements. `expiresAt` permet les blocages temporaires (ex: 7 jours). Le lien vers `moderatedBy` assure la traçabilité.

```typescript
async getUserOrderHistory(
  userId: string,
  filters: OrderFiltersDto
): Promise<PaginatedResult<Order>> {
  const { page = 1, limit = 20, status, startDate, endDate, minAmount, maxAmount } = filters;

  // Vérifier que l'utilisateur existe
  const user = await this.userRepository.findOne({ where: { id: userId } });
  if (!user) {
    throw new NotFoundException('Utilisateur non trouvé');
  }

  const query = this.orderRepository
    .createQueryBuilder('order')
    .leftJoinAndSelect('order.items', 'items')
    .where('order.userId = :userId', { userId });

  if (status) {
    query.andWhere('order.status = :status', { status });
  }

  if (startDate) {
    query.andWhere('order.createdAt >= :startDate', { startDate });
  }

  if (endDate) {
    query.andWhere('order.createdAt <= :endDate', { endDate });
  }

  if (minAmount) {
    query.andWhere('order.total >= :minAmount', { minAmount });
  }

  if (maxAmount) {
    query.andWhere('order.total <= :maxAmount', { maxAmount });
  }

  const [data, total] = await query
    .orderBy('order.createdAt', 'DESC')
    .skip((page - 1) * limit)
    .take(limit)
    .getManyAndCount();

  return {
    data,
    meta: {
      total,
      page,
      lastPage: Math.ceil(total / limit),
      limit,
    },
  };
}
